#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    // Create rotation matrices
    mat3 rotX = mat3(
        1, 0, 0,
        0, cos(q1), -sin(q1),
        0, sin(q1), cos(q1)
    );

    mat3 rotY = mat3(
        cos(q2), 0, sin(q2),
        0, 1, 0,
        -sin(q2), 0, cos(q2)
    );

    mat3 rotZ = mat3(
        cos(q3), -sin(q3), 0,
        sin(q3), cos(q3), 0,
        0, 0, 1
    );

    // Create cube vertices
    vec3 pos = vec3(vUv.x * 2 - 1, vUv.y * 2 - 1, 1);
    pos.z = .5;  // Set initial Z position

    // Apply rotations
    pos = multiply(rotX, pos);
    pos = multiply(rotY, pos);
    pos = multiply(rotZ, pos);

    // Project to screen space
    ret = vec3(pos.xy / (pos.z + 2), pos.z);

    // Calculate face normal for texturing
    vec3 normal = normalize(pos);

    // Generate unique texture per face based on normal direction
    vec3 color;
    if (abs(normal.x) > abs(normal.y) && abs(normal.x) > abs(normal.z)) {
        // X-facing sides
        color = mix(
            vec3(1,0,0),
            vec3(0,1,0),
            (sin(uTime*0.1 + vUv.x*3) + 1)*0.5
        );
    } else if (abs(normal.y) > abs(normal.z)) {
        // Y-facing sides
        color = mix(
            vec3(0,1,0),
            vec3(0,0,1),
            (sin(uTime*0.15 + vUv.y*3) + 1)*0.5
        );
    } else {
        // Z-facing sides
        color = mix(
            vec3(1,0,1),
            vec3(1,1,0),
            (sin(uTime*0.2 + dot(vUv,vUv)*3) + 1)*0.5
        );
    }

    // Add audio reactivity
    //color *= 1 + audioLow*0.5;
    //color += audioMid*0.3;

    // Add depth-based shading
    float depth = (pos.z + 2) * 0.25;
    color *= depth;

    ret = color;

  fragColor = ret;
}

